frappe.ui.form.on("Purchase Receipt Item", {
  item_code(frm, cdt, cdn) {
    const row = locals[cdt][cdn];
    if (!row.item_code) return;

    frappe.db.get_value("Item", row.item_code, "custom_is_reconfigurable")
      .then(r => {
        const is_reconf = (r.message && r.message.custom_is_reconfigurable) ? 1 : 0;
        
        frappe.db.get_value("Item", row.item_code, "custom_sheet_length_mm")
        .then(r => {
          
          frappe.model.set_value(cdt, cdn, "custom_sheet_length_mm", r.message.custom_sheet_length_mm);
          
        });
        frappe.db.get_value("Item", row.item_code, "custom_sheet_width_mm")
        .then(r => {
          
          frappe.model.set_value(cdt, cdn, "custom_sheet_width_mm", r.message.custom_sheet_width_mm);
          
        });

      });
  }
});

frappe.ui.form.on("Purchase Receipt", {
  validate(frm) {
    (frm.doc.items || []).forEach(row => {
      if (!row.item_code) return;

      // Quick client-side check; server-side will enforce strictly
      // (avoid async call here).
      if (row.custom_sheet_length_mm && row.custom_sheet_width_mm) return;
    });
  }
});

frappe.ui.form.on('Sales Order', {
	refresh(frm) {
		// your code here
	}
});

frappe.ui.form.on("Sales Order Item", {
  item_code(frm, cdt, cdn) {
    const row = locals[cdt][cdn];
    if (!row.item_code) return;

    frappe.db.get_value("Item", row.item_code, "custom_requires_dimensions")
      .then(r => {
        const needs_dim = (r.message && r.message.custom_requires_dimensions) ? 1 : 0;
        if (!needs_dim) return;

        if (!row.custom_client_length_mm) {
          frappe.db.get_value("Item", row.item_code, "custom_client_length_mm")
            .then(r => {
              frappe.model.set_value(cdt, cdn, "custom_client_length_mm", r.message.custom_client_length_mm);
            });
        }

        if (!row.custom_client_width_mm) {
          frappe.db.get_value("Item", row.item_code, "custom_client_width_mm")
            .then(r => {
              frappe.model.set_value(cdt, cdn, "custom_client_width_mm", r.message.custom_client_width_mm);
            });
        }
      });
  }
});
